// Determine role-based prompt strategy
const leadData = $input.first().json;
const title = (leadData.title || '').toLowerCase();
const email = String(leadData.email || '').toLowerCase().trim();

// Keep support inbox out of Instantly outreach
if (email === 'support@mynilwealthstrategies.com' || email === 'support@mynilwealthstrategis.com') {
  return [];
}

// Detect role
let role = 'administrator';
if (title.includes('athletic director') || title.includes('ad ')) {
  role = 'athletic_director';
} else if (title.includes('coach') || title.includes('head coach')) {
  role = 'coach';
} else if (title.includes('compliance') || title.includes('nil coordinator')) {
  role = 'compliance';
}

// Role-specific prompts
const rolePrompts = {
  athletic_director: `You're reaching out to an Athletic Director who oversees entire athletic programs. Focus on:
- Program-wide NIL wealth management solutions
- Risk mitigation for the entire department
- Compliance and liability concerns
- How protecting athletes protects the program's reputation`,

  coach: `You're reaching out to a Coach who cares deeply about individual athletes. Focus on:
- Protecting their players' NIL earnings
- Real stories of athletes losing money to bad advice
- How this helps recruit better players (parents ask about financial protection)
- Simple, no-hassle setup for their team`,

  compliance: `You're reaching out to a Compliance/NIL Coordinator. Focus on:
- Regulatory compliance and documentation
- Reducing administrative burden
- Creating standardized financial education for athletes
- Integration with existing NIL processes`,

  administrator: `You're reaching out to an Athletic Administrator. Focus on:
- Comprehensive financial protection for student-athletes
- Institutional liability reduction
- Supporting the athletic department's mission
- Easy implementation across multiple sports`
};

return [{
  json: {
    ...leadData,
    role: role,
    role_prompt: rolePrompts[role]
  }
}];

