// Extract all 3 versions and best selection
const leadData = $('Detect Role & Strategy').item.json;
const allVersions = JSON.parse($('Generate 3 Email Versions').item.json.choices[0].message.content);
const bestSelection = JSON.parse($input.first().json.choices[0].message.content);

return [{
  json: {
    lead_id: leadData.id,
    email: leadData.email,
    first_name: leadData.full_name.split(' ')[0],
    last_name: leadData.full_name.split(' ').slice(1).join(' ') || '',
    organization: leadData.organization,
    title: leadData.title,
    role: leadData.role,
    state: leadData.state,

    // Store all 3 versions for regenerate feature
    email_v1_subject: allVersions.v1.subject,
    email_v1_body: allVersions.v1.body,
    email_v2_subject: allVersions.v2.subject,
    email_v2_body: allVersions.v2.body,
    email_v3_subject: allVersions.v3.subject,
    email_v3_body: allVersions.v3.body,

    // Best selected version
    best_version: bestSelection.best,
    selected_subject: bestSelection.subject,
    selected_body: bestSelection.body,
    selection_reason: bestSelection.reason
  }
}];

// Summarize outreach batch
const allResults = $input.all();
const summary = {
  total_sent: allResults.length,
  timestamp: new Date().toISOString()
};

return [{ json: summary }];

